package com.lightdelta.lightdelta

import android.content.Context
import android.content.pm.PackageManager
import android.os.Build
import android.util.Log
import java.io.File
import java.io.FileOutputStream
import java.io.InputStream
import java.io.OutputStream
import java.lang.reflect.Method
import java.util.zip.ZipFile

object NativeLibLoader {
    private const val TAG = "NativeLibLoader"
    private const val LIB_NAME = "lightdelta"

    fun load(context: Context) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            // Android 11+ uses scoped storage, cannot directly write to lib path
            // So we extract to cache dir and load manually
            try {
                val abiList = Build.SUPPORTED_ABIS
                val libName = abiList.firstOrNull()?.let { abi ->
                    when {
                        abi.startsWith("armeabi-v7a") -> "armeabi-v7a"
                        abi.startsWith("arm64-v8a") -> "arm64-v8a"
                        abi.startsWith("x86") -> abi
                        else -> null
                    }
                } ?: return

                val libFile = File(context.cacheDir, "lib$LIB_NAME.so")
                if (!libFile.exists()) {
                    extractAsset(context, "lib/$libName/lib$LIB_NAME.so", libFile)
                }
                System.load(libFile.absolutePath)
                Log.d(TAG, "Loaded native library from cache")
            } catch (e: Exception) {
                Log.e(TAG, "Failed to load native library", e)
            }
        } else {
            // Android 10 and below can directly load from libs folder
            try {
                System.loadLibrary(LIB_NAME)
                Log.d(TAG, "Loaded native library from libs")
            } .catch (e: Exception) {
                Log.e(TAG, "Failed to load native library", e)
            }
        }
    }

    private fun extractAsset(context: Context, assetPath: String, dest: File) {
        try {
            context.assets.open(assetPath).use { input ->
                FileOutputStream(dest).use { output ->
                    input.copyTo(output)
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "Failed to extract asset: $assetPath", e)
        }
    }
}
